WHERE w.user_id = #{userId}
  AND w.status = 2
  AND w.is_deleted = 0
  AND w.work_date BETWEEN #{startDate} AND #{endDate}
ORDER BY w.work_date ASC, w.work_id ASC


WHERE u.dept_id = #{deptId}
  AND w.status = 2
  AND w.is_deleted = 0
